<script setup lang="ts">
import { computed,onMounted,reactive,ref,watch } from 'vue'
const emit=defineEmits<{alert:[msg:string,type?:'success'|'error']}>()
const sources=ref<any[]>([]),orders=ref<any[]>([]),materials=ref<any[]>([]),processes=ref<any[]>([]),confirmDetail=ref<any>(null),detailBusy=ref(false),selectedBomId=ref<number|''>(''),tab=ref<'sample'|'bulk'>('sample'),busy=ref(false),aiBusy=ref(false),budget=ref<any>(null),aiAdvice=ref<any>(null)
const edit=reactive<any>({productName:'',plannedQty:100,targetPrice:0,remark:'',materials:[],processes:[]})
const form=reactive({quantity:3,targetMarginRate:45,unitPrice:0,customerName:'',contactName:'',contactPhone:'',receiverAddress:'',requirement:''})
const selected=computed(()=>sources.value.find(x=>Number(x.bomId)===Number(selectedBomId.value)))
const visibleOrders=computed(()=>orders.value.filter(x=>x.orderType===tab.value));const statusText:any={pending_confirm:'待客户确认',confirmed:'已确认待下单',producing:'生产中',ready_to_ship:'待发货',shipped:'已发货',completed:'已完成',cancelled:'已取消'}
async function load(){try{const [r,m,p]=await Promise.all([fetch('/api/production/workbench'),fetch('/api/production/materials'),fetch('/api/production/processes')]);const d=await r.json();sources.value=d.sources;orders.value=d.orders;materials.value=await m.json();processes.value=await p.json();if(!selectedBomId.value&&sources.value.length)selectBom(sources.value[0].bomId)}catch(e:any){emit('alert','加载失败：'+e.message,'error')}}
function selectBom(id:number){selectedBomId.value=id;const s=selected.value;if(!s)return;edit.productName=s.productName;edit.plannedQty=s.plannedQty;edit.targetPrice=Number(s.targetPrice||0);edit.remark=s.remark||'';edit.materials=(s.materials||[]).map((x:any)=>({materialId:x.materialId,qty:Number(x.qty),lossRate:Number(x.lossRate),remark:x.remark||''}));edit.processes=(s.processes||[]).map((x:any)=>({processId:x.processId,qty:Number(x.qty),remark:x.remark||''}));form.quantity=tab.value==='sample'?3:(s.plannedQty||100);form.unitPrice=Number(s.targetPrice||0);form.customerName=s.customerName||'';form.contactName=s.contactName||'';form.contactPhone=s.contactPhone||'';form.receiverAddress=s.receiverAddress||'';budget.value=null}
function switchTab(t:'sample'|'bulk'){tab.value=t;form.quantity=t==='sample'?3:(selected.value?.plannedQty||100);budget.value=null}
function mat(id:any){return materials.value.find(x=>Number(x.id)===Number(id))||{}} function proc(id:any){return processes.value.find(x=>Number(x.id)===Number(id))||{}}
function materialUnitCost(m:any){return Number(m.qty||0)*(1+Number(m.lossRate||0))*Number(mat(m.materialId).standardCost||0)}
function materialBatchCost(m:any){return materialUnitCost(m)*Number(form.quantity||0)}
function processUnitCost(x:any){return Number(x.qty||0)*Number(proc(x.processId).standardCost||0)}
function processBatchCost(x:any){return processUnitCost(x)*Number(form.quantity||0)}
const liveMaterialTotal=computed(()=>edit.materials.reduce((sum:number,m:any)=>sum+materialBatchCost(m),0))
const liveProcessTotal=computed(()=>edit.processes.reduce((sum:number,x:any)=>sum+processBatchCost(x),0))
const liveDirectTotal=computed(()=>liveMaterialTotal.value+liveProcessTotal.value)
function money(v:any){return Number(v||0).toFixed(2)}
function addMaterial(){if(materials.value[0])edit.materials.push({materialId:materials.value[0].id,qty:1,lossRate:.03,remark:''})} function addProcess(){if(processes.value[0])edit.processes.push({processId:processes.value[0].id,qty:1,remark:''})}
async function aiGenerate(){if(!selected.value)return;aiBusy.value=true;try{const r=await fetch(`/api/production/boms/${selected.value.bomId}/ai-plan`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({quantity:form.quantity,mode:tab.value,requirement:form.requirement})});if(!r.ok)throw new Error(await r.text());const d=await r.json();aiAdvice.value=d;edit.materials=(d.materials||[]).map((x:any)=>({materialId:x.materialId||x.id,qty:Number(x.qty),lossRate:Number(x.lossRate||0),remark:x.remark||''}));edit.processes=(d.processes||[]).map((x:any)=>({processId:x.processId||x.id,qty:Number(x.qty),remark:x.remark||''}));emit('alert','AI已生成生产BOM草案，请人工审核修改后保存','success')}catch(e:any){emit('alert','AI规划失败：'+e.message,'error')}finally{aiBusy.value=false}}
async function saveBom(){if(!selected.value)return false;busy.value=true;try{const salesInput={customerName:form.customerName,contactName:form.contactName,contactPhone:form.contactPhone,receiverAddress:form.receiverAddress,requirement:form.requirement,quantity:form.quantity,unitPrice:form.unitPrice,targetMarginRate:form.targetMarginRate};const r=await fetch(`/api/production/boms/${selected.value.bomId}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(edit)});if(!r.ok)throw new Error(await r.text());await load();Object.assign(form,salesInput);emit('alert','BOM物料与工艺路线已保存，客户及订单信息已保留','success');return true}catch(e:any){emit('alert','保存失败：'+e.message,'error');return false}finally{busy.value=false}}
async function calculate(){if(!selected.value)return false;const saved=await saveBom();if(!saved)return false;try{const r=await fetch('/api/production/quotes/simulate',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({bomId:selected.value.bomId,quantity:form.quantity,overheadRate:tab.value==='sample'?.18:.12,targetMarginRate:form.targetMarginRate/100})});if(!r.ok)throw new Error(await r.text());budget.value=await r.json();emit('alert','具体生产预算已核算','success');return true}catch(e:any){emit('alert','预算核算失败：'+e.message,'error');return false}}
async function createOrder(){if(!budget.value){const calculated=await calculate();if(!calculated)return}if(!selected.value||!budget.value)return;busy.value=true;try{const body={orderType:tab.value,bomId:selected.value.bomId,projectId:selected.value.projectId,projectSkuId:selected.value.projectSkuId,quantity:form.quantity,targetMarginRate:form.targetMarginRate/100,unitPrice:form.unitPrice||budget.value.suggestedPrice,customerName:form.customerName,contactName:form.contactName,contactPhone:form.contactPhone,receiverAddress:form.receiverAddress,productionRequirement:form.requirement};const r=await fetch('/api/production/commercial-orders',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});if(!r.ok)throw new Error(await r.text());const d=await r.json();emit('alert',`报价及订单已生成：${d.orderNo}`,'success');await load()}catch(e:any){emit('alert','生成订单失败：'+e.message,'error')}finally{busy.value=false}}
async function openConfirm(id:number){detailBusy.value=true;try{const r=await fetch(`/api/production/commercial-orders/${id}`);if(!r.ok)throw new Error(await r.text());confirmDetail.value=await r.json()}catch(e:any){emit('alert','订单详情加载失败：'+e.message,'error')}finally{detailBusy.value=false}}
async function confirmSelected(){if(!confirmDetail.value)return;const id=confirmDetail.value.id;confirmDetail.value=null;await action(id,'confirm')}
async function action(id:number,name:string){busy.value=true;try{const r=await fetch(`/api/production/commercial-orders/${id}/${name}`,{method:'POST'});if(!r.ok)throw new Error(await r.text());emit('alert',name==='confirm'?'订单已确认':name==='start'?'生产任务已下达':'已完工待发货','success');await load()}catch(e:any){emit('alert',e.message,'error')}finally{busy.value=false}}
watch(()=>form.quantity,()=>budget.value=null);watch(()=>[edit.materials,edit.processes],()=>budget.value=null,{deep:true});onMounted(load)
</script>
<template><div class="page flow-page">
<header class="hero"><div><p>PROJECT → BOM → QUOTE → ORDER → PRODUCTION → LOGISTICS</p><h2>项目订单生产中心</h2><span>项目制开发产出的 BOM 在这里进入商业闭环；打样与大货共用统一订单号，仅按业务区分流。</span></div><button class="btn btn-secondary" @click="load">刷新</button></header>
<div class="steps"><b>1 选择项目BOM</b><b>2 生成详细报价</b><b>3 客户确认订单</b><b>4 下达打样/大货</b><b>5 完工待发货</b><b>6 订单号绑定物流</b></div>
<div class="layout"><aside class="card source"><h3>项目 / BOM 待办</h3><button v-for="s in sources" :key="s.bomId" :class="{active:Number(selectedBomId)===Number(s.bomId)}" @click="selectBom(s.bomId)"><b>{{s.projectName||'独立生产方案'}}</b><span>{{s.skuName||s.productName}}</span><small>{{s.projectNo||'未关联项目'}} · {{s.bomNo}}</small></button><div v-if="!sources.length" class="empty">项目制开发完成 BOM 后将在这里出现</div></aside>
<main><section v-if="selected" class="card"><div class="head"><div><h3>{{selected.productName}}</h3><p>{{selected.projectName||'独立生产方案'}} · {{selected.bomNo}}</p></div><div class="tabs"><button :class="{active:tab==='sample'}" @click="switchTab('sample')">详细报价打样</button><button :class="{active:tab==='bulk'}" @click="switchTab('bulk')">详细报价大货</button></div></div>
<div class="ai-bar"><input v-model="form.requirement" placeholder="输入特殊要求：材质、尺寸、包装、交期、质量标准等"><button class="btn btn-primary" :disabled="aiBusy" @click="aiGenerate">{{aiBusy?'AI规划中...':'AI生成物料、工艺和预算建议'}}</button></div><div v-if="aiAdvice" class="advice"><b>AI预算建议：</b>{{aiAdvice.budgetAdvice}}<br><b>风险提示：</b>{{aiAdvice.riskAdvice}} <small>模型：{{aiAdvice.model}}</small></div>
<div class="bom-editor"><div><div class="editor-head"><b>物料明细（可人工修改）</b><button @click="addMaterial">+ 物料</button></div><table><thead><tr><th>物料</th><th>单件用量</th><th>损耗%</th><th>标准单价</th><th>单件成本</th><th>本批成本</th><th></th></tr></thead><tbody><tr v-for="(m,i) in edit.materials" :key="i"><td><select v-model.number="m.materialId"><option v-for="x in materials" :value="x.id">{{x.name}} / {{x.unit}}</option></select></td><td><input type="number" step="0.01" v-model.number="m.qty"></td><td><input type="number" step="0.1" :value="m.lossRate*100" @input="m.lossRate=Number(($event.target as HTMLInputElement).value)/100"></td><td>¥{{money(mat(m.materialId).standardCost||0)}}/{{mat(m.materialId).unit}}</td><td class="cost">¥{{money(materialUnitCost(m))}}</td><td class="cost">¥{{money(materialBatchCost(m))}}</td><td><button @click="edit.materials.splice(i,1)">删除</button></td></tr></tbody></table></div><div><div class="editor-head"><b>工艺路线（可人工排序修改）</b><button @click="addProcess">+ 工艺</button></div><table><thead><tr><th>顺序/工艺</th><th>次数</th><th>标准单价</th><th>单件成本</th><th>本批成本</th><th></th></tr></thead><tbody><tr v-for="(x,i) in edit.processes" :key="i"><td><span>{{Number(i)+1}}.</span><select v-model.number="x.processId"><option v-for="p in processes" :value="p.id">{{p.name}}</option></select></td><td><input type="number" step="0.1" v-model.number="x.qty"></td><td>¥{{money(proc(x.processId).standardCost||0)}}</td><td class="cost">¥{{money(processUnitCost(x))}}</td><td class="cost">¥{{money(processBatchCost(x))}}</td><td><button @click="edit.processes.splice(i,1)">删除</button></td></tr></tbody></table></div></div><div class="live-cost"><div><span>当前数量</span><b>{{form.quantity}} 件</b></div><div><span>物料实时预估</span><b>¥{{money(liveMaterialTotal)}}</b></div><div><span>工艺实时预估</span><b>¥{{money(liveProcessTotal)}}</b></div><div><span>直接成本实时预估</span><b>¥{{money(liveDirectTotal)}}</b></div></div><p class="cost-tip">实时预估会随单件用量、损耗率、工艺次数和生产数量立即变化；正式预算需点击“保存并核算”。</p><div class="editor-actions"><button class="btn" @click="saveBom">保存人工调整</button><button class="btn btn-primary" @click="calculate">保存并核算{{tab==='sample'?'打样':'大货'}}预算</button></div><div class="form"><label>数量<input type="number" v-model.number="form.quantity"></label><label>目标毛利 %<input type="number" v-model.number="form.targetMarginRate"></label><label>客户成交单价（0=系统建议）<input type="number" step="0.01" v-model.number="form.unitPrice"></label><label>客户/公司<input v-model="form.customerName"></label><label>联系人<input v-model="form.contactName"></label><label>联系电话<input v-model="form.contactPhone"></label><label class="wide">收货地址<input v-model="form.receiverAddress"></label></div><div v-if="budget" class="budget"><div><span>物料总成本</span><b>¥{{budget.materialUnitCost}} × {{budget.quantity}}</b></div><div><span>工艺总成本</span><b>¥{{budget.processUnitCost}} × {{budget.quantity}}</b></div><div><span>包装单件</span><b>¥{{budget.packagingUnitCost}}</b></div><div><span>管理损耗单件</span><b>¥{{budget.overheadUnitCost}}</b></div><div><span>生产总预算</span><b>¥{{budget.totalCost}}</b></div><div><span>单件综合成本</span><b>¥{{budget.unitCost}}</b></div><div><span>建议销售单价</span><b>¥{{budget.suggestedPrice}}</b></div><div><span>目标毛利</span><b>{{(budget.grossMarginRate*100).toFixed(1)}}%</b></div></div><button class="btn btn-primary" :disabled="busy" @click="createOrder">生成详细报价并创建{{tab==='sample'?'打样':'大货'}}订单</button></section>
<section class="card orders"><div class="head"><div><h3>统一订单履约</h3><p>订单号不区分打样/大货，下面按业务区展示</p></div><div class="tabs"><button :class="{active:tab==='sample'}" @click="switchTab('sample')">打样区</button><button :class="{active:tab==='bulk'}" @click="switchTab('bulk')">大货区</button></div></div>
<div v-for="o in visibleOrders" :key="o.id" class="order"><div><b>{{o.orderNo}}</b><span class="tag">{{tab==='sample'?'打样':'大货'}}</span><em :class="o.status">{{statusText[o.status]||o.status}}</em><p>{{o.projectName||'独立订单'}} / {{o.productName}} · {{o.quantity}}件 · ¥{{o.totalAmount}}</p><small>报价 {{o.quoteNo}} <template v-if="o.sampleNo">· 打样任务 {{o.sampleNo}}</template><template v-if="o.productionNo">· 生产任务 {{o.productionNo}}</template></small></div><div class="actions"><button v-if="o.status==='pending_confirm'" @click="openConfirm(o.id)">查看详情并确认</button><button v-if="o.status==='confirmed'" @click="action(o.id,'start')">下达生产</button><button v-if="o.status==='producing'" @click="action(o.id,'ready')">生产完工</button><span v-if="o.status==='ready_to_ship'">请到“物流跟踪”按此订单号发货</span></div></div><div v-if="!visibleOrders.length" class="empty">暂无{{tab==='sample'?'打样':'大货'}}订单</div></section></main></div><div v-if="confirmDetail" class="modal-mask" @click.self="confirmDetail=null"><div class="confirm-modal"><div class="modal-head"><div><small>订单确认审核</small><h2>{{confirmDetail.orderNo}}</h2><p>请核对客户、BOM、成本与成交金额，确认后才允许下达生产。</p></div><button @click="confirmDetail=null">×</button></div><div class="review-grid"><section><h3>订单与客户</h3><dl><dt>业务类型</dt><dd>{{confirmDetail.orderType==='sample'?'打样订单':'大货订单'}}</dd><dt>产品</dt><dd>{{confirmDetail.productName}}</dd><dt>人工生产要求</dt><dd class="requirement">{{confirmDetail.productionRequirement||'未填写特殊生产要求'}}</dd><dt>数量</dt><dd>{{confirmDetail.quantity}} 件</dd><dt>客户</dt><dd>{{confirmDetail.customerName||'-'}}</dd><dt>联系人</dt><dd>{{confirmDetail.contactName||'-'}} / {{confirmDetail.contactPhone||'-'}}</dd><dt>收货地址</dt><dd>{{confirmDetail.receiverAddress||'-'}}</dd></dl></section><section><h3>报价汇总</h3><dl><dt>报价单号</dt><dd>{{confirmDetail.quote?.quoteNo}}</dd><dt>物料成本</dt><dd>¥{{money(confirmDetail.quote?.materialCost)}}</dd><dt>工艺成本</dt><dd>¥{{money(confirmDetail.quote?.processCost)}}</dd><dt>包装成本</dt><dd>¥{{money(confirmDetail.quote?.packagingCost)}}</dd><dt>管理损耗</dt><dd>¥{{money(confirmDetail.quote?.overheadCost)}}</dd><dt>生产总成本</dt><dd>¥{{money(confirmDetail.quote?.totalCost)}}</dd><dt>客户成交单价</dt><dd class="strong">¥{{money(confirmDetail.unitPrice)}}</dd><dt>订单成交金额</dt><dd class="strong">¥{{money(confirmDetail.totalAmount)}}</dd></dl></section></div><section class="review-table"><h3>物料成本明细</h3><table><thead><tr><th>物料</th><th>单件用量</th><th>损耗</th><th>标准单价</th><th>单件成本</th><th>本单成本</th><th>人工备注</th></tr></thead><tbody><tr v-for="m in confirmDetail.materials" :key="m.id"><td>{{m.name}}</td><td>{{m.qty}} {{m.unit}}</td><td>{{money(m.lossRate*100)}}%</td><td>¥{{money(m.unitCost)}}</td><td>¥{{money(Number(m.qty)*(1+Number(m.lossRate))*Number(m.unitCost))}}</td><td>¥{{money(Number(m.qty)*(1+Number(m.lossRate))*Number(m.unitCost)*confirmDetail.quantity)}}</td><td>{{m.remark||'-'}}</td></tr></tbody></table></section><section class="review-table"><h3>工艺路线明细</h3><table><thead><tr><th>顺序</th><th>工艺</th><th>次数</th><th>标准单价</th><th>本单成本</th><th>人工备注</th></tr></thead><tbody><tr v-for="(x,i) in confirmDetail.processes" :key="x.id"><td>{{Number(i)+1}}</td><td>{{x.name}}</td><td>{{x.qty}}</td><td>¥{{money(x.unitCost)}}</td><td>¥{{money(Number(x.qty)*Number(x.unitCost)*confirmDetail.quantity)}}</td><td>{{x.remark||'-'}}</td></tr></tbody></table></section><div class="confirm-warning">确认后订单将锁定为“已确认待下单”，下一步才能下达{{confirmDetail.orderType==='sample'?'打样':'大货'}}生产任务。</div><div class="modal-actions"><button class="btn" @click="confirmDetail=null">暂不确认，返回修改</button><button class="btn btn-primary" :disabled="busy" @click="confirmSelected">明细无误，确认订单</button></div></div></div></div></template>
<style scoped>.flow-page{background:#f5f7fb;min-height:100vh}.hero{display:flex;justify-content:space-between;padding:26px;border-radius:20px;background:linear-gradient(135deg,#172554,#4c1d95,#0f766e);color:#fff}.hero p{font-size:11px;letter-spacing:1.5px}.hero h2{margin:6px 0}.hero span{opacity:.85}.steps{display:grid;grid-template-columns:repeat(6,1fr);gap:8px;margin:16px 0}.steps b{padding:13px 8px;background:#fff;border:1px solid #ddd6fe;border-radius:12px;font-size:12px;text-align:center;color:#5b21b6}.layout{display:grid;grid-template-columns:280px 1fr;gap:16px}.card{background:#fff;border:1px solid #e2e8f0;border-radius:18px;padding:18px;margin-bottom:16px}.source button{display:flex;width:100%;text-align:left;flex-direction:column;gap:4px;padding:12px;margin:8px 0;border:1px solid #e2e8f0;background:#fff;border-radius:12px;cursor:pointer}.source button.active{border-color:#7c3aed;background:#faf5ff}.source span,.source small,p,small{color:#64748b}.head{display:flex;justify-content:space-between;gap:15px;align-items:flex-start}.head h3{margin:0}.tabs{display:flex;gap:6px}.tabs button,.actions button{border:0;padding:9px 12px;border-radius:9px;cursor:pointer;font-weight:700}.tabs button.active{background:#6d28d9;color:#fff}.bom{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:15px 0}.bom>div{padding:12px;background:#f8fafc;border-radius:12px}.bom span{display:block;font-size:12px;color:#475569;margin-top:6px}.form{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:14px 0}.form label{font-size:12px;font-weight:700;color:#475569}.form input{display:block;width:100%;box-sizing:border-box;height:40px;margin-top:5px;border:1px solid #cbd5e1;border-radius:9px;padding:0 10px}.wide{grid-column:span 3}.order{display:flex;justify-content:space-between;align-items:center;border-top:1px solid #eef2f7;padding:14px 0}.order b{font-size:16px}.tag,em{font-style:normal;margin-left:8px;padding:3px 8px;border-radius:999px;font-size:11px;background:#ede9fe